INSERT INTO gap_analysis_templates (id, name, framework, description, importance, scope, is_active, is_custom, created_at, updated_at)
VALUES
  ('b1a2c3d4-1111-4aaa-bbbb-111111111111', 'IEC 60601-1:2012 — General Safety and Essential Performance', 'IEC_60601_1', 'General requirements for basic safety and essential performance of medical electrical equipment. Covers electrical, mechanical, radiation, temperature hazards, PEMS, construction and ME systems.', 'high', 'product', true, false, now(), now()),
  ('b1a2c3d4-2222-4aaa-bbbb-222222222222', 'IEC 60601-1-2:2014 — EMC Requirements and Tests', 'IEC_60601_1_2', 'Electromagnetic compatibility requirements and tests for medical electrical equipment and systems. Covers emissions, immunity, risk management for EMC, and accompanying documents.', 'high', 'product', true, false, now(), now()),
  ('b1a2c3d4-3333-4aaa-bbbb-333333333333', 'IEC 60601-1-6 — Usability Engineering', 'IEC_60601_1_6', 'Collateral standard for usability engineering of medical electrical equipment. Covers USE specification, hazard-related use scenarios, formative and summative evaluation.', 'high', 'product', true, false, now(), now()),
  ('b1a2c3d4-4444-4aaa-bbbb-444444444444', 'IEC 62304 — Software Life Cycle Processes', 'IEC_62304', 'Software life cycle processes for medical device software. Covers development, maintenance, risk management, configuration management, and problem resolution.', 'high', 'product', true, false, now(), now()),
  ('b1a2c3d4-5555-4aaa-bbbb-555555555555', 'IEC 20957 — Stationary Training Equipment', 'IEC_20957', 'Safety requirements for stationary training equipment. Covers general safety, stability, strength/durability, labelling, instructions, and display accuracy.', 'medium', 'product', true, false, now(), now());
